declare(strict_types=1);require __DIR__.'/admin-core.php';require __DIR__.'/prospect-model.php';$canon=ho_salesportal_canon();$fieldList=implode("\n",$canon['claim_fields']);$reqList=implode("\n",$canon['requirements']);$confidenceList=implode(', ',$canon['confidence_levels']);$prompt="Research this business using the Hoosier Online Sales Portal schema.\n\nBusiness to research:\n[PASTE BUSINESS NAME, WEBSITE, FACEBOOK PAGE, GOOGLE PROFILE, OR NOTES HERE]\n\nReturn ONLY valid JSON. Do not include markdown. Do not include commentary.\n\nUse this exact top-level structure:\n{\n  \"business\": {\n    \"business_slug\": \"\",\n    \"business_name_current\": \"\",\n    \"business_type\": \"\",\n    \"location_city\": \"\",\n    \"location_state\": \"IN\",\n    \"service_area_text\": \"\"\n  },\n  \"evidence_sources\": [],\n  \"claims\": [],\n  \"marketing_clearance\": {\n    \"business_activity_score\": 0,\n    \"need_score\": 0,\n    \"fit_score\": 0,\n    \"confidence_score\": 0,\n    \"contactability_score\": 0,\n    \"buildability_score\": 0,\n    \"marketing_clearance_score\": 0,\n    \"marketing_clearance_status\": \"hold\",\n    \"recommended_package\": \"unknown\",\n    \"recommended_design\": \"\",\n    \"reason\": \"\"\n  },\n  \"notes\": []\n}\n\nEach evidence_sources item should use: source_type, source_url, source_title, capture_status, raw_excerpt, notes.\nEach claims item should use: field_key, claim_value, normalized_value, confidence_level, confidence_score, claim_status, source_type, source_url, source_label, evidence_note, supports_me_category, supports_requirement_key, evidence_source_index.\n\nUse ONLY these field_key values:\n$fieldList\n\nUse ONLY these supports_requirement_key values:\n$reqList\n\nUse ONLY these confidence_level values:\n$confidenceList\n\nRules:\n- Do not invent field keys.\n- Do not use owner_name unless clearly supported.\n- If uncertain, use lower confidence and explain in evidence_note.\n- Every claim should include source_type and evidence_note.\n- Store customer consequences in evidence_note when describing weaknesses.\n- If a fact is not verified enough for outreach, mark it inferred or weak_inference.\n- Prefer business name over owner name unless owner confidence is high.\n- Be strict. The output must be importable JSON.";ho_admin_render_start('portal','Sales Research Prompts','Sales portal','Research <em>Prompts</em>','Copy this prompt into GPT, then paste the JSON response into Sales Intake.');?>
<section class="admin-card"><h2>GPT Research Prompt</h2><textarea id="promptBox" style="width:100%;min-height:560px;border-radius:18px;border:1px solid var(--ho-border);padding:16px;font:14px/1.45 ui-monospace,Menlo,Consolas,monospace;"><?=ho_h($prompt)?></textarea><p><button class="admin-btn admin-btn-primary" type="button" onclick="navigator.clipboard.writeText(document.getElementById('promptBox').value)">Copy Prompt</button></p></section><?php ho_admin_render_end();?>
